import { page, render } from "#test/browser"
import { Text } from "../text"
import { Show } from "./show"

describe("<Show />", () => {
  test("renders component correctly", async () => {
    await render(
      <Show fallback="World" when>
        Hello
      </Show>,
    )

    await expect.element(page.getByText("Hello")).toBeInTheDocument()
  })

  test("renders fallback when when is false", async () => {
    await render(
      <Show fallback="World" when={false}>
        Hello
      </Show>,
    )

    await expect.element(page.getByText("World")).toBeInTheDocument()
  })

  test("renders children with function pattern", async () => {
    await render(<Show when={{ name: "John" }}>{(when) => when.name}</Show>)

    await expect.element(page.getByText("John")).toBeInTheDocument()
  })

  test("renders children with Element", async () => {
    await render(
      <Show fallback="World" when>
        <Text>Hello</Text>
      </Show>,
    )

    await expect.element(page.getByText("Hello")).toBeInTheDocument()
  })

  test("renders nothing when when is false and no fallback is provided", async () => {
    await render(<Show when={false}>Hello</Show>)

    await expect
      .element(page.getByText("Hello").query())
      .not.toBeInTheDocument()
  })

  test("renders nothing when when is null and no fallback is provided", async () => {
    await render(<Show when={null}>Hello</Show>)

    await expect
      .element(page.getByText("Hello").query())
      .not.toBeInTheDocument()
  })
})

import type { ReactNode } from "react"
import type { ReactNodeOrFunction } from "@yamada-ui/react"
import { isValidElement } from "react"
import { runIfFn } from "@yamada-ui/react"

export interface ShowProps<Y> {
  /**
   * The children to render if `when` is `true`
   */
  children: ReactNodeOrFunction<Y>
  /**
   * The fallback content to render if `when` is `false`
   */
  fallback?: ReactNode
  /**
   * If `true`, it'll render the `children` prop
   */
  when?: null | Y
}

/**
 * `Show` is a component that shows or hides its children based on a condition.
 *
 * @see https://yamada-ui.com/docs/components/show
 */
export const Show = <Y,>({
  children,
  fallback,
  when,
}: ShowProps<Y>): ReactNode => {
  let result: ReactNode

  if (!when) {
    result = fallback
  } else {
    result = runIfFn(children, when)
  }

  return isValidElement(result) ? result : <>{result}</>
}
